void printArmstrongNumbers() {
    for (int i = 1; i <= 500; i++) {
        int original = i;
        int sum = 0;
        int temp = i;
        while (temp > 0) {
            int digit = temp % 10;
            sum += (digit * digit * digit);
            temp /= 10;
        }
        if (sum == original) {
            printf("%d\n", original);
        }
    }
}

double compute_cosine(double x, int n) {
    double result = 1.0;
    double term = 1.0;
    int sign = -1;
    for (int i = 2; i <= n; i += 2) {
        term *= (x * x) / ((double)i * (i - 1));
        result += sign * term;
        sign *= -1;
    }
    return result;
}

