void printFibonacci(int n) {
    long long t1 = 0, t2 = 1, nextTerm;
    for (int i = 1; i <= n; ++i) {
        printf("%lld%s", t1, (i == n ? "" : " "));
        nextTerm = t1 + t2;
        t1 = t2;
        t2 = nextTerm;
    }
}

