int binarySearch(int AR[], int target, int N) {
    int low = 0, high = N - 1;
    while (low <= high) {
        int mid = low + (high - low) / 2;
        if (AR[mid] == target)
            return 1;
        if (AR[mid] < target)
            low = mid + 1;
        else
            high = mid - 1;
    }
    return 0;
}

